 5→//! JJK chalk command - empty commits marking steeplechase events
 6→//!
 7→//! The chalk command creates empty commits with special formatting for tracking
 8→//! steeplechase events like approach, wrap, fly, or heat-level discussions.
 9→
10→#[allow(unused_imports)]
11→use std::fmt::Write;
12→
13→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark};
14→use crate::jjrn_notch::{jjrn_ChalkMarker as ChalkMarker, jjrn_format_chalk_message, jjrn_format_heat_discussion};
15→
16→/// Arguments for jjx_chalk command
17→#[derive(clap::Args, Debug)]
18→pub struct jjrx_ChalkArgs {
19→    /// Identity: Coronet (pace-level) or Firemark (heat-level discussion only)
20→    pub identity: String,
21→
22→    /// Marker type: A(pproach), W(rap), F(ly), d(iscussion)
23→    #[arg(long)]
24→    pub marker: String,
25→
26→    /// Marker description text
27→    #[arg(long)]
28→    pub description: String,
29→}
30→
31→/// Run the chalk command - create steeplechase marker commit
32→pub fn jjrx_run_chalk(args: jjrx_ChalkArgs) -> (i32, String) {
33→    let mut buf = String::new();
34→
35→    let marker = match ChalkMarker::jjrn_parse(&args.marker) {
36→        Ok(m) => m,
37→        Err(e) => {
38→            jjbuf!(buf, "jjx_chalk: error: {}", e);
39→            return (1, buf);
40→        }
41→    };
42→
43→    // Try parsing as Coronet first (5 base64 chars), then as Firemark (2 base64 chars)
44→    let identity = args.identity.strip_prefix('₢').or_else(|| args.identity.strip_prefix('₣')).unwrap_or(&args.identity);
45→
46→    let message = if identity.len() == 5 {
47→        // Coronet - pace-level chalk
48→        let coronet = match Coronet::jjrf_parse(&args.identity) {
49→            Ok(c) => c,
50→            Err(e) => {
51→                jjbuf!(buf, "jjx_chalk: error: {}", e);
52→                return (1, buf);
53→            }
54→        };
55→        jjrn_format_chalk_message(&coronet, marker, &args.description)
56→    } else if identity.len() == 2 {
57→        // Firemark - heat-level (discussion, session)
58→        if marker.jjrn_requires_pace() {
59→            jjbuf!(buf, "jjx_chalk: error: {} marker requires a Coronet (pace identity), not a Firemark", marker.jjrn_as_str());
60→            return (1, buf);
61→        }
62→        let firemark = match Firemark::jjrf_parse(&args.identity) {
63→            Ok(fm) => fm,
64→            Err(e) => {
65→                jjbuf!(buf, "jjx_chalk: error: {}", e);
66→                return (1, buf);
67→            }
68→        };
69→
70→        jjrn_format_heat_discussion(&firemark, &args.description)
71→    } else {
72→        jjbuf!(buf, "jjx_chalk: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
73→        return (1, buf);
74→    };
75→
76→    let commit_args = vvc::vvcc_CommitArgs {
77→        prefix: None,
78→        message: Some(message),
79→        allow_empty: true,
80→        no_stage: true,
81→        size_limit: vvc::VVCG_SIZE_LIMIT,
82→        warn_limit: vvc::VVCG_WARN_LIMIT,
83→    };
84→
85→    (vvc::commit(&commit_args), buf)
86→}
87→

