  5→//! Garland command - celebrate heat completion and create continuation
  6→//!
  7→//! Garlanding a heat:
  8→//! - Updates source heat silks to garlanded form and status to stabled
  9→//! - Creates new heat with continuation silks, status racing
 10→//! - Transfers actionable paces (rough/bridled) to new heat
 11→//! - Retains complete/abandoned paces in garlanded heat
 12→
 13→use std::fmt::Write;
 14→use std::path::PathBuf;
 15→
 16→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_GarlandArgs as LibGarlandArgs};
 17→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
 18→use crate::jjri_io::jjri_paddock_path;
 19→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 20→
 21→/// Arguments for jjx_garland command
 22→#[derive(clap::Args, Debug)]
 23→pub struct jjrgl_GarlandArgs {
 24→    /// Path to the Gallops JSON file
 25→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 26→    pub file: PathBuf,
 27→
 28→    /// Heat to garland (Firemark)
 29→    pub firemark: String,
 30→}
 31→
 32→/// Run the garland command
 33→///
 34→/// Executes garland operation, saves gallops, and commits the result.
 35→/// Returns exit code (0 for success, non-zero for failure).
 36→pub fn jjrgl_run_garland(args: jjrgl_GarlandArgs) -> (i32, String) {
 37→    use std::path::Path;
 38→    let mut buf = String::new();
 39→
 40→    // Acquire lock FIRST - fail fast if another operation is in progress
 41→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 42→        Ok(l) => l,
 43→        Err(e) => {
 44→            jjbuf!(buf, "jjx_garland: error: {}", e);
 45→            return (1, buf);
 46→        }
 47→    };
 48→
 49→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 50→        Ok(g) => g,
 51→        Err(e) => {
 52→            jjbuf!(buf, "jjx_garland: error loading Gallops: {}", e);
 53→            return (1, buf);
 54→        }
 55→    };
 56→
 57→    let firemark_str = args.firemark.clone();
 58→
 59→    // Compute base path from gallops file
 60→    let base_path = args.file.parent()
 61→        .and_then(|p| p.parent())
 62→        .and_then(|p| p.parent())
 63→        .unwrap_or(Path::new("."));
 64→
 65→    let garland_args = LibGarlandArgs {
 66→        firemark: firemark_str.clone(),
 67→    };
 68→
 69→    // Execute garland operation
 70→    let result = match gallops.jjrg_garland(garland_args, base_path) {
 71→        Ok(r) => r,
 72→        Err(e) => {
 73→            jjbuf!(buf, "jjx_garland: error: {}", e);
 74→            return (1, buf);
 75→        }
 76→    };
 77→
 78→    // Save gallops
 79→    if let Err(e) = gallops.jjrg_save(&args.file) {
 80→        jjbuf!(buf, "jjx_garland: error saving Gallops: {}", e);
 81→        return (1, buf);
 82→    }
 83→
 84→    // Parse both firemarks for commit file list
 85→    let old_fm = Firemark::jjrf_parse(&result.old_firemark).expect("garland returned invalid old firemark");
 86→    let new_fm = Firemark::jjrf_parse(&result.new_firemark).expect("garland returned invalid new firemark");
 87→
 88→    let gallops_path = args.file.to_string_lossy().to_string();
 89→    let old_paddock_path = jjri_paddock_path(old_fm.jjrf_as_str());
 90→    let new_paddock_path = jjri_paddock_path(new_fm.jjrf_as_str());
 91→
 92→    // Build commit message using heat-level Garland action
 93→    let commit_message = format_heat_message(
 94→        &old_fm,
 95→        HeatAction::Garland,
 96→        &format!("{} → {}", result.old_silks, result.new_silks)
 97→    );
 98→
 99→    let commit_args = vvc::vvcm_CommitArgs {
100→        files: vec![
101→            gallops_path,
102→            old_paddock_path,
103→            new_paddock_path,
104→        ],
105→        message: commit_message,
106→        size_limit: 100000,  // 100KB - paddock files can be large
107→        warn_limit: 50000,
108→    };
109→
110→    match vvc::machine_commit(&lock, &commit_args) {
111→        Ok(hash) => {
112→            jjbuf!(buf, "jjx_garland: committed {}", &hash[..8]);
113→        }
114→        Err(e) => {
115→            jjbuf!(buf, "jjx_garland: commit warning: {}", e);
116→        }
117→    }
118→
119→    // Output JSON result
120→    let output = serde_json::json!({
121→        "old_firemark": result.old_firemark,
122→        "old_silks": result.old_silks,
123→        "new_firemark": result.new_firemark,
124→        "new_silks": result.new_silks,
125→        "paces_transferred": result.paces_transferred,
126→        "paces_retained": result.paces_retained,
127→    });
128→
129→    match serde_json::to_string_pretty(&output) {
130→        Ok(json) => {
131→            let _ = writeln!(buf, "{}", json);
132→            (0, buf)
133→        }
134→        Err(e) => {
135→            jjbuf!(buf, "jjx_garland: error serializing output: {}", e);
136→            (1, buf)
137→        }
138→    }
139→    // lock released here
140→}
141→

