 5→//! Validate command - Schema validation for Gallops JSON
 6→//!
 7→//! This module owns the validate command's Args struct and handler function.
 8→
 9→use std::fmt::Write;
10→use std::path::PathBuf;
11→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
12→
13→/// Arguments for jjx_validate command
14→#[derive(clap::Args, Debug)]
15→pub struct jjrvl_ValidateArgs {
16→    /// Path to the Gallops JSON file
17→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
18→    pub file: PathBuf,
19→}
20→
21→/// Run the validate command - validate Gallops JSON schema
22→pub fn jjrvl_run_validate(args: jjrvl_ValidateArgs) -> (i32, String) {
23→    let mut buf = String::new();
24→
25→    let gallops = match Gallops::jjrg_load(&args.file) {
26→        Ok(g) => g,
27→        Err(e) => {
28→            jjbuf!(buf, "jjx_validate: error loading Gallops: {}", e);
29→            return (1, buf);
30→        }
31→    };
32→
33→    match gallops.jjrg_validate() {
34→        Ok(()) => {
35→            let _ = writeln!(buf, "Gallops validation passed");
36→            (0, buf)
37→        }
38→        Err(errors) => {
39→            jjbuf!(buf, "jjx_validate: validation failed with {} error(s):", errors.len());
40→            for error in errors {
41→                jjbuf!(buf, "  - {}", error);
42→            }
43→            (1, buf)
44→        }
45→    }
46→}
47→

