  5→//! Restring command - bulk draft multiple paces between heats
  6→//!
  7→//! Handles the jjx_restring command which moves multiple paces from one heat
  8→//! to another in a single atomic operation.
  9→
 10→use std::path::PathBuf;
 11→
 12→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RestringArgs as LibRestringArgs, jjrg_PaceState};
 14→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 15→
 16→/// Arguments for jjx_restring command
 17→#[derive(clap::Args, Debug)]
 18→pub struct jjrrs_RestringArgs {
 19→    /// Path to the Gallops JSON file
 20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 21→    pub file: PathBuf,
 22→
 23→    /// Source Heat identity (Firemark)
 24→    pub firemark: String,
 25→
 26→    /// Destination Heat identity (Firemark)
 27→    #[arg(long)]
 28→    pub to: String,
 29→}
 30→
 31→/// Execute restring command - bulk draft multiple paces atomically
 32→pub fn jjrrs_run(args: jjrrs_RestringArgs, coronets: String) -> (i32, String) {
 33→    let mut buf = String::new();
 34→
 35→    // Acquire lock FIRST - fail fast if another operation is in progress
 36→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 37→        Ok(l) => l,
 38→        Err(e) => {
 39→            jjbuf!(buf, "jjx_restring: error: {}", e);
 40→            return (1, buf);
 41→        }
 42→    };
 43→
 44→    let coronets: Vec<String> = match serde_json::from_str(&coronets) {
 45→        Ok(c) => c,
 46→        Err(e) => {
 47→            jjbuf!(buf, "jjx_restring: error: Expected JSON array of coronets: {}", e);
 48→            return (1, buf);
 49→        }
 50→    };
 51→
 52→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 53→        Ok(g) => g,
 54→        Err(e) => {
 55→            jjbuf!(buf, "jjx_restring: error loading Gallops: {}", e);
 56→            return (1, buf);
 57→        }
 58→    };
 59→
 60→    let restring_args = LibRestringArgs {
 61→        source_firemark: args.firemark.clone(),
 62→        dest_firemark: args.to.clone(),
 63→        coronets,
 64→    };
 65→
 66→    // Execute restring operation
 67→    let result = match gallops.jjrg_restring(restring_args) {
 68→        Ok(r) => r,
 69→        Err(e) => {
 70→            jjbuf!(buf, "jjx_restring: error: {}", e);
 71→            return (1, buf);
 72→        }
 73→    };
 74→
 75→    // Save gallops
 76→    if let Err(e) = gallops.jjrg_save(&args.file) {
 77→        jjbuf!(buf, "jjx_restring: error saving Gallops: {}", e);
 78→        return (1, buf);
 79→    }
 80→
 81→    // Parse both firemarks for commit file list
 82→    let dest_fm = Firemark::jjrf_parse(&result.dest_firemark).expect("restring returned invalid dest firemark");
 83→
 84→    let gallops_path = args.file.to_string_lossy().to_string();
 85→    let source_paddock_path = result.source_paddock.clone();
 86→    let dest_paddock_path = result.dest_paddock.clone();
 87→
 88→    // Build commit message using heat-level action
 89→    let commit_message = format_heat_message(
 90→        &dest_fm,
 91→        HeatAction::Draft,  // Reusing Draft action since this is a bulk draft operation
 92→        &format!("restring {} paces from {}", result.drafted.len(), result.source_firemark)
 93→    );
 94→
 95→    let commit_args = vvc::vvcm_CommitArgs {
 96→        files: vec![
 97→            gallops_path,
 98→            source_paddock_path,
 99→            dest_paddock_path,
100→        ],
101→        message: commit_message,
102→        size_limit: 100000,  // 100KB - bulk operations can be large
103→        warn_limit: 50000,
104→    };
105→
106→    match vvc::machine_commit(&lock, &commit_args) {
107→        Ok(hash) => {
108→            jjbuf!(buf, "jjx_restring: committed {}", &hash[..8]);
109→        }
110→        Err(e) => {
111→            jjbuf!(buf, "jjx_restring: commit warning: {}", e);
112→        }
113→    }
114→
115→    // Output JSON result
116→    let drafted_json: Vec<_> = result.drafted.iter().map(|m| {
117→        serde_json::json!({
118→            "old_coronet": m.old_coronet,
119→            "new_coronet": m.new_coronet,
120→            "silks": m.silks,
121→            "state": match m.state {
122→                jjrg_PaceState::Rough => "rough",
123→                jjrg_PaceState::Bridled => "bridled",
124→                jjrg_PaceState::Complete => "complete",
125→                jjrg_PaceState::Abandoned => "abandoned",
126→            },
127→            "spec": m.spec,
128→        })
129→    }).collect();
130→
131→    let output = serde_json::json!({
132→        "source": {
133→            "firemark": result.source_firemark,
134→            "silks": result.source_silks,
135→            "paddock": result.source_paddock,
136→            "empty_after": result.source_empty_after,
137→        },
138→        "destination": {
139→            "firemark": result.dest_firemark,
140→            "silks": result.dest_silks,
141→            "paddock": result.dest_paddock,
142→        },
143→        "drafted": drafted_json,
144→    });
145→
146→    match serde_json::to_string_pretty(&output) {
147→        Ok(json) => {
148→            jjbuf!(buf, "{}", json);
149→            (0, buf)
150→        }
151→        Err(e) => {
152→            jjbuf!(buf, "jjx_restring: error serializing output: {}", e);
153→            (1, buf)
154→        }
155→    }
156→    // lock released here
157→}
