116→            vvco_err!(output, "jjx_garland: commit warning: {}", e);
117→        }
118→    }
119→
120→    // Output JSON result
121→    let json_result = serde_json::json!({
122→        "old_firemark": result.old_firemark,
123→        "old_silks": result.old_silks,
124→        "new_firemark": result.new_firemark,
125→        "new_silks": result.new_silks,
126→        "paces_transferred": result.paces_transferred,
127→        "paces_retained": result.paces_retained,
128→    });
129→
130→    match serde_json::to_string_pretty(&json_result) {
131→        Ok(json) => {
132→            vvco_out!(output, "{}", json);
133→            (0, output.vvco_finish())
134→        }
135→        Err(e) => {
136→            vvco_err!(output, "jjx_garland: error serializing output: {}", e);
137→            (1, output.vvco_finish())
138→        }
139→    }
140→    // lock released here
141→}
