11→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops};
13→
14→/// Arguments for jjx_curry command
15→#[derive(clap::Args, Debug)]
16→pub struct jjrcu_CurryArgs {
17→    /// Path to the Gallops JSON file
18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
19→    pub file: PathBuf,
20→
21→    /// Target Heat identity (Firemark)
22→    pub firemark: String,
23→
24→    /// Optional note for chalk entry
25→    #[arg(long)]
26→    pub note: Option<String>,
27→}
28→
29→/// Handler for jjx_curry command
30→pub fn jjrcu_run_curry(args: jjrcu_CurryArgs, content: Option<String>) -> (i32, String) {
31→    use crate::jjro_ops::jjrg_curry;
32→
33→    let mut output = vvco_Output::buffer();
34→
35→    // Parse firemark
36→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
37→        Ok(fm) => fm,
38→        Err(e) => {
39→            vvco_err!(output, "jjx_curry: error: {}", e);
40→            return (1, output.vvco_finish());
41→        }
42→    };
43→
44→    match content {
45→        None => {
46→            // Getter mode: display paddock content
47→            let gallops = match Gallops::jjrg_load(&args.file) {
48→                Ok(g) => g,
49→                Err(e) => {
50→                    vvco_err!(output, "jjx_curry: error loading Gallops: {}", e);
51→                    return (1, output.vvco_finish());
52→                }
53→            };
54→
55→            let firemark_key = firemark.jjrf_display();
56→            let heat = match gallops.heats.get(&firemark_key) {
57→                Some(h) => h,
58→                None => {
59→                    vvco_err!(output, "jjx_curry: error: Heat '{}' not found", firemark_key);
60→                    return (1, output.vvco_finish());
61→                }
62→            };
63→
64→            let paddock_path = std::path::Path::new(&heat.paddock_file);
65→            let paddock_content = match std::fs::read_to_string(paddock_path) {
66→                Ok(c) => c,
