 5→//! Landing command - record agent landing after autonomous execution
 6→//!
 7→//! The landing command creates an empty commit recording when an autonomous agent
 8→//! completes execution of a bridled pace. The commit message uses the L (landing)
 9→//! marker in the steeplechase format.
10→
11→use clap::Args;
12→use vvc::{vvco_out, vvco_err, vvco_Output};
13→use crate::jjrf_favor::jjrf_Coronet as Coronet;
14→use crate::jjrn_notch::jjrn_format_landing_message;
15→
16→/// Arguments for jjx_landing command
17→#[derive(Args, Debug)]
18→pub struct jjrld_LandingArgs {
19→    /// Pace identity (Coronet)
20→    pub coronet: String,
21→
22→    /// Agent tier that executed the pace
23→    pub agent: String,
24→}
25→
26→/// Execute the landing command
27→///
28→/// Creates an empty commit with L marker recording when an agent completes
29→/// execution of a bridled pace. Content is the agent completion report.
30→///
31→/// Returns exit code (0 for success, non-zero for failure).
32→pub fn jjrld_run_landing(args: jjrld_LandingArgs, content: String) -> (i32, String) {
33→    let mut output = vvco_Output::buffer();
34→
35→    // Parse coronet
36→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
37→        Ok(c) => c,
38→        Err(e) => {
39→            vvco_err!(output, "jjx_landing: error: {}", e);
40→            return (1, output.vvco_finish());
41→        }
42→    };
43→
44→    // Use jjrn_format_landing_message to create the commit message, with content as body
45→    let base_message = jjrn_format_landing_message(&coronet, &args.agent);
46→    let message = if content.trim().is_empty() {
47→        base_message
48→    } else {
49→        format!("{}\n\n{}", base_message, content.trim())
50→    };
51→
52→    // Create empty landing commit
53→    let commit_args = vvc::vvcc_CommitArgs {
54→        prefix: None,
55→        message: Some(message),
56→        allow_empty: true,
57→        no_stage: true,
58→        size_limit: vvc::VVCG_SIZE_LIMIT,
59→        warn_limit: vvc::VVCG_WARN_LIMIT,
60→    };
61→
62→    let rc = vvc::commit(&commit_args, &mut output);
63→    (rc, output.vvco_finish())
64→}
