  5→//! Column table formatting for JJK output
  6→//!
  7→//! Provides structured column layout to eliminate magic numbers/strings
  8→//! from formatted output operations. Single source of truth for headers,
  9→//! widths, and alignment.
 10→
 11→use vvc::{vvco_out, vvco_Output};
 12→
 13→/// Gap between columns
 14→pub const JJRP_COLUMN_GAP: usize = 2;
 15→
 16→/// Minimum column width
 17→pub const JJRP_MIN_WIDTH: usize = 5;
 18→
 19→/// Column alignment
 20→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 21→pub enum jjrp_Align {
 22→    Left,
 23→    Right,
 24→}
 25→
 26→/// Column definition
 27→#[derive(Debug, Clone)]
 28→pub struct jjrp_Column {
 29→    /// Header text (single source of truth)
 30→    pub header: &'static str,
 31→    /// Minimum width (defaults to header.len())
 32→    pub min_width: usize,
 33→    /// Alignment
 34→    pub align: jjrp_Align,
 35→}
 36→
 37→impl jjrp_Column {
 38→    /// Create a new column with default min_width from header
 39→    pub fn new(header: &'static str, align: jjrp_Align) -> Self {
 40→        Self {
 41→            header,
 42→            min_width: header.len().max(JJRP_MIN_WIDTH),
 43→            align,
 44→        }
 45→    }
 46→
 47→    /// Create a new column with explicit min_width
 48→    pub fn with_width(header: &'static str, min_width: usize, align: jjrp_Align) -> Self {
 49→        Self {
 50→            header,
 51→            min_width: min_width.max(JJRP_MIN_WIDTH),
 52→            align,
 53→        }
 54→    }
 55→}
 56→
 57→/// Table with columns and computed widths
 58→pub struct jjrp_Table {
 59→    columns: Vec<jjrp_Column>,
 60→    widths: Vec<usize>,
 61→}
 62→
 63→impl jjrp_Table {
 64→    /// Create a new table with the given columns
 65→    pub fn jjrp_new(columns: Vec<jjrp_Column>) -> Self {
 66→        let widths = columns.iter().map(|c| c.min_width).collect();
 67→        Self { columns, widths }
 68→    }
 69→
 70→    /// Update column widths based on a data row
 71→    pub fn jjrp_measure(&mut self, row: &[&str]) {
 72→        for (i, value) in row.iter().enumerate() {
 73→            if i < self.widths.len() {
 74→                self.widths[i] = self.widths[i].max(value.len());
 75→            }
 76→        }
 77→    }
 78→
 79→    /// Write the header row to output
 80→    pub fn jjrp_write_header(&self, output: &mut vvco_Output) {
 81→        let mut parts = Vec::new();
 82→        for (i, col) in self.columns.iter().enumerate() {
 83→            let width = self.widths[i];
 84→            let formatted = match col.align {
 85→                jjrp_Align::Left => format!("{:<width$}", col.header, width = width),
 86→                jjrp_Align::Right => format!("{:>width$}", col.header, width = width),
 87→            };
 88→            parts.push(formatted);
 89→        }
 90→        vvco_out!(output, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
 91→    }
 92→
 93→    /// Write a separator line to output
 94→    /// Uses box drawing character to avoid markdown interpretation of dashes
 95→    pub fn jjrp_write_separator(&self, output: &mut vvco_Output) {
 96→        let mut parts = Vec::new();
 97→        for width in &self.widths {
 98→            parts.push("─".repeat(*width));
 99→        }
100→        vvco_out!(output, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
101→    }
102→
103→    /// Write a data row to output
104→    pub fn jjrp_write_row(&self, output: &mut vvco_Output, values: &[&str]) {
105→        let mut parts = Vec::new();
106→        for (i, value) in values.iter().enumerate() {
107→            if i < self.columns.len() {
108→                let width = self.widths[i];
109→                let col = &self.columns[i];
110→                let formatted = match col.align {
111→                    jjrp_Align::Left => format!("{:<width$}", value, width = width),
112→                    jjrp_Align::Right => format!("{:>width$}", value, width = width),
113→                };
114→                parts.push(formatted);
115→            }
116→        }
117→        vvco_out!(output, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
118→    }
119→}
120→
121→#[cfg(test)]
122→mod tests {
123→    use super::*;
124→
125→    #[test]
126→    fn test_column_new() {
127→        let col = jjrp_Column::new("Test", jjrp_Align::Left);
128→        assert_eq!(col.header, "Test");
129→        assert_eq!(col.min_width, JJRP_MIN_WIDTH);
130→        assert_eq!(col.align, jjrp_Align::Left);
131→    }
132→
133→    #[test]
134→    fn test_column_with_width() {
135→        let col = jjrp_Column::with_width("ID", 10, jjrp_Align::Right);
136→        assert_eq!(col.header, "ID");
137→        assert_eq!(col.min_width, 10);
138→        assert_eq!(col.align, jjrp_Align::Right);
139→    }
140→
141→    #[test]
142→    fn test_table_measure() {
143→        let columns = vec![
144→            jjrp_Column::new("Name", jjrp_Align::Left),
145→            jjrp_Column::new("ID", jjrp_Align::Right),
146→        ];
147→        let mut table = jjrp_Table::jjrp_new(columns);
148→
149→        // Initial widths are min_width
150→        assert_eq!(table.widths[0], JJRP_MIN_WIDTH);
151→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH);
152→
153→        // Measure a row with longer values
154→        table.jjrp_measure(&["Very Long Name", "12345"]);
155→        assert_eq!(table.widths[0], 14); // "Very Long Name".len()
156→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH); // Still min because "12345" is shorter
157→    }
158→
159→    #[test]
160→    fn test_table_output() {
161→        let columns = vec![
162→            jjrp_Column::new("₣Fire", jjrp_Align::Left),
163→            jjrp_Column::new("Silks", jjrp_Align::Left),
164→            jjrp_Column::new("Count", jjrp_Align::Right),
165→        ];
166→        let mut table = jjrp_Table::jjrp_new(columns);
167→
168→        // Measure some data
169→        table.jjrp_measure(&["₣AB", "test-heat", "42"]);
170→        table.jjrp_measure(&["₣CD", "another-heat-name", "100"]);
171→
172→        // Write to output and verify they don't panic
173→        let mut output = vvco_Output::buffer();
174→        table.jjrp_write_header(&mut output);
175→        table.jjrp_write_separator(&mut output);
176→        table.jjrp_write_row(&mut output, &["₣AB", "test-heat", "42"]);
177→        table.jjrp_write_row(&mut output, &["₣CD", "another-heat-name", "100"]);
178→        let text = output.vvco_finish();
179→        assert!(!text.is_empty());
180→    }
181→}
