 5→//! GetCoronets command - List Coronets for a Heat
 6→//!
 7→//! Queries a Gallops JSON file and outputs coronets (pace identities) for a specified heat,
 8→//! with optional filtering for remaining or rough paces only.
 9→
10→use vvc::{vvco_out, vvco_err, vvco_Output};
11→use crate::jjrf_favor::jjrf_Firemark as Firemark;
12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
13→use std::path::PathBuf;
14→
15→/// Arguments for jjx_get_coronets command
16→#[derive(clap::Args, Debug)]
17→pub struct jjrgc_GetCoronetsArgs {
18→    /// Path to the Gallops JSON file
19→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
20→    pub file: PathBuf,
21→
22→    /// Target Heat identity (Firemark)
23→    pub firemark: String,
24→
25→    /// Exclude complete and abandoned paces
26→    #[arg(long)]
27→    pub remaining: bool,
28→
29→    /// Include only rough paces
30→    #[arg(long)]
31→    pub rough: bool,
32→}
33→
34→/// Run the get_coronets command - output coronets one per line
35→pub fn jjrgc_run_get_coronets(args: jjrgc_GetCoronetsArgs) -> (i32, String) {
36→    let mut output = vvco_Output::buffer();
37→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
38→        Ok(fm) => fm,
39→        Err(e) => {
40→            vvco_err!(output, "jjx_get_coronets: error: {}", e);
41→            return (1, output.vvco_finish());
42→        }
43→    };
44→
45→    let gallops = match Gallops::jjrg_load(&args.file) {
46→        Ok(g) => g,
47→        Err(e) => {
48→            vvco_err!(output, "jjx_get_coronets: error: {}", e);
49→            return (1, output.vvco_finish());
50→        }
51→    };
52→
53→    let heat_key = firemark.jjrf_display();
54→    let heat = match gallops.heats.get(&heat_key) {
55→        Some(h) => h,
56→        None => {
57→            vvco_err!(output, "jjx_get_coronets: error: Heat '{}' not found", heat_key);
58→            return (1, output.vvco_finish());
59→        }
60→    };
61→
62→    for coronet_key in &heat.order {
63→        if let Some(pace) = heat.paces.get(coronet_key) {
64→            if let Some(tack) = pace.tacks.first() {
65→                // Apply --remaining filter: skip complete/abandoned
66→                if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
67→                    continue;
68→                }
69→                // Apply --rough filter: only include rough
70→                if args.rough && tack.state != PaceState::Rough {
71→                    continue;
72→                }
73→                vvco_out!(output, "{}", coronet_key);
74→            }
75→        }
76→    }
77→
78→    (0, output.vvco_finish())
79→}
