  5→//! Muster command - List all Heats with summary information
  6→//!
  7→//! Implements the muster query operation which displays all heats
  8→//! with their status and pace completion counts.
  9→
 10→use std::path::PathBuf;
 11→use vvc::{vvco_out, vvco_err, vvco_Output};
 12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 13→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 14→
 15→/// Arguments for muster command
 16→#[derive(clap::Args, Debug)]
 17→pub struct jjrmu_MusterArgs {
 18→    /// Path to the Gallops JSON file
 19→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 20→    pub file: PathBuf,
 21→
 22→    /// Filter by heat status (racing, stabled)
 23→    #[arg(long)]
 24→    pub status: Option<String>,
 25→}
 26→
 27→/// Run the muster command - list Heats as TSV
 28→pub async fn jjrmu_run_muster(args: jjrmu_MusterArgs) -> (i32, String) {
 29→    let mut output = vvco_Output::buffer();
 30→    let gallops = match Gallops::jjrg_load(&args.file) {
 31→        Ok(g) => g,
 32→        Err(e) => {
 33→            vvco_err!(output, "jjx_muster: error: {}", e);
 34→            return (1, output.vvco_finish());
 35→        }
 36→    };
 37→
 38→    // Collect heats in heat_order sequence (explicit user-defined priority order)
 39→    let ordered_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
 40→        .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
 41→        .collect();
 42→
 43→    // Apply status filter if specified
 44→    let heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = if let Some(ref filter_status) = args.status {
 45→        let filter_lowercase = filter_status.to_lowercase();
 46→        ordered_heats.into_iter().filter(|(_, heat)| {
 47→            let heat_status_str = match heat.status {
 48→                HeatStatus::Racing => "racing",
 49→                HeatStatus::Stabled => "stabled",
 50→                HeatStatus::Retired => "retired",
 51→            };
 52→            heat_status_str == filter_lowercase
 53→        }).collect()
 54→    } else {
 55→        ordered_heats
 56→    };
 57→
 58→    // Set up table with column definitions
 59→    let mut table = jjrp_Table::jjrp_new(vec![
 60→        jjrp_Column::new("₣Fire", jjrp_Align::Left),
 61→        jjrp_Column::new("Silks", jjrp_Align::Left),
 62→        jjrp_Column::new("Status", jjrp_Align::Left),
 63→        jjrp_Column::new("Done", jjrp_Align::Right),
 64→        jjrp_Column::new("Total", jjrp_Align::Right),
 65→    ]);
 66→
 67→    // Measure all rows to compute column widths
 68→    for (key, heat) in &heats_by_status {
 69→        // Count paces where state != Abandoned
 70→        let defined_count = heat.paces.values().filter(|pace| {
 71→            if let Some(tack) = pace.tacks.first() {
 72→                tack.state != PaceState::Abandoned
 73→            } else {
 74→                true
 75→            }
 76→        }).count();
 77→
 78→        // Count paces where state == Complete
 79→        let completed_count = heat.paces.values().filter(|pace| {
 80→            if let Some(tack) = pace.tacks.first() {
 81→                tack.state == PaceState::Complete
 82→            } else {
 83→                false
 84→            }
 85→        }).count();
 86→
 87→        let status_str = match heat.status {
 88→            HeatStatus::Racing => "racing",
 89→            HeatStatus::Stabled => "stabled",
 90→            HeatStatus::Retired => "retired",
 91→        };
 92→
 93→        table.jjrp_measure(&[
 94→            key,
 95→            &heat.silks,
 96→            status_str,
 97→            &completed_count.to_string(),
 98→            &defined_count.to_string(),
 99→        ]);
100→    }
101→
102→    // Print header and separator
103→    table.jjrp_write_header(&mut output);
104→    table.jjrp_write_separator(&mut output);
105→
106→    // Print data rows
107→    for (key, heat) in heats_by_status {
108→        // Count paces where state != Abandoned
109→        let defined_count = heat.paces.values().filter(|pace| {
110→            if let Some(tack) = pace.tacks.first() {
111→                tack.state != PaceState::Abandoned
112→            } else {
113→                true
114→            }
115→        }).count();
116→
117→        // Count paces where state == Complete
118→        let completed_count = heat.paces.values().filter(|pace| {
119→            if let Some(tack) = pace.tacks.first() {
120→                tack.state == PaceState::Complete
121→            } else {
122→                false
123→            }
124→        }).count();
125→
126→        let status_str = match heat.status {
127→            HeatStatus::Racing => "racing",
128→            HeatStatus::Stabled => "stabled",
129→            HeatStatus::Retired => "retired",
130→        };
131→
132→        table.jjrp_write_row(&mut output, &[
133→            key,
134→            &heat.silks,
135→            status_str,
136→            &completed_count.to_string(),
137→            &defined_count.to_string(),
138→        ]);
139→    }
140→
141→    if let Err(e) = vvc::vvcp_invitatory().await {
142→        vvco_err!(output, "jjx_muster: warning: invitatory failed: {}", e);
143→    }
144→
145→    (0, output.vvco_finish())
146→}
