  5→//! Restring command - bulk draft multiple paces between heats
  6→//!
  7→//! Handles the jjx_restring command which moves multiple paces from one heat
  8→//! to another in a single atomic operation.
  9→
 10→use std::path::PathBuf;
 11→
 12→use vvc::{vvco_out, vvco_err, vvco_Output};
 13→
 14→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RestringArgs as LibRestringArgs, jjrg_PaceState};
 16→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 17→
 18→/// Arguments for jjx_restring command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrrs_RestringArgs {
 21→    /// Path to the Gallops JSON file
 22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 23→    pub file: PathBuf,
 24→
 25→    /// Source Heat identity (Firemark)
 26→    pub firemark: String,
 27→
 28→    /// Destination Heat identity (Firemark)
 29→    #[arg(long)]
 30→    pub to: String,
 31→}
 32→
 33→/// Execute restring command - bulk draft multiple paces atomically
 34→pub fn jjrrs_run(args: jjrrs_RestringArgs, coronets: String) -> (i32, String) {
 35→    let mut output = vvco_Output::buffer();
 36→
 37→    // Acquire lock FIRST - fail fast if another operation is in progress
 38→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 39→        Ok(l) => l,
 40→        Err(e) => {
 41→            vvco_err!(output, "jjx_restring: error: {}", e);
 42→            return (1, output.vvco_finish());
 43→        }
 44→    };
 45→
 46→    let coronets: Vec<String> = match serde_json::from_str(&coronets) {
 47→        Ok(c) => c,
 48→        Err(e) => {
 49→            vvco_err!(output, "jjx_restring: error: Expected JSON array of coronets: {}", e);
 50→            return (1, output.vvco_finish());
 51→        }
 52→    };
 53→
 54→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 55→        Ok(g) => g,
 56→        Err(e) => {
 57→            vvco_err!(output, "jjx_restring: error loading Gallops: {}", e);
 58→            return (1, output.vvco_finish());
 59→        }
 60→    };
 61→
 62→    let restring_args = LibRestringArgs {
 63→        source_firemark: args.firemark.clone(),
 64→        dest_firemark: args.to.clone(),
 65→        coronets,
 66→    };
 67→
 68→    // Execute restring operation
 69→    let result = match gallops.jjrg_restring(restring_args) {
 70→        Ok(r) => r,
 71→        Err(e) => {
 72→            vvco_err!(output, "jjx_restring: error: {}", e);
 73→            return (1, output.vvco_finish());
 74→        }
 75→    };
 76→
 77→    // Save gallops
 78→    if let Err(e) = gallops.jjrg_save(&args.file) {
 79→        vvco_err!(output, "jjx_restring: error saving Gallops: {}", e);
 80→        return (1, output.vvco_finish());
 81→    }
 82→
 83→    // Parse both firemarks for commit file list
 84→    let dest_fm = Firemark::jjrf_parse(&result.dest_firemark).expect("restring returned invalid dest firemark");
 85→
 86→    let gallops_path = args.file.to_string_lossy().to_string();
 87→    let source_paddock_path = result.source_paddock.clone();
 88→    let dest_paddock_path = result.dest_paddock.clone();
 89→
 90→    // Build commit message using heat-level action
 91→    let commit_message = format_heat_message(
 92→        &dest_fm,
 93→        HeatAction::Draft,  // Reusing Draft action since this is a bulk draft operation
 94→        &format!("restring {} paces from {}", result.drafted.len(), result.source_firemark)
 95→    );
 96→
 97→    let commit_args = vvc::vvcm_CommitArgs {
 98→        files: vec![
 99→            gallops_path,
100→            source_paddock_path,
101→            dest_paddock_path,
102→        ],
103→        message: commit_message,
104→        size_limit: 100000,  // 100KB - bulk operations can be large
105→        warn_limit: 50000,
106→    };
107→
108→    match vvc::machine_commit(&lock, &commit_args, &mut output) {
109→        Ok(hash) => {
110→            vvco_out!(output, "jjx_restring: committed {}", &hash[..8]);
111→        }
112→        Err(e) => {
113→            vvco_err!(output, "jjx_restring: commit warning: {}", e);
114→        }
115→    }
116→
117→    // Output JSON result
118→    let drafted_json: Vec<_> = result.drafted.iter().map(|m| {
119→        serde_json::json!({
120→            "old_coronet": m.old_coronet,
121→            "new_coronet": m.new_coronet,
122→            "silks": m.silks,
123→            "state": match m.state {
124→                jjrg_PaceState::Rough => "rough",
125→                jjrg_PaceState::Bridled => "bridled",
126→                jjrg_PaceState::Complete => "complete",
127→                jjrg_PaceState::Abandoned => "abandoned",
128→            },
129→            "spec": m.spec,
130→        })
131→    }).collect();
132→
133→    let json_result = serde_json::json!({
134→        "source": {
135→            "firemark": result.source_firemark,
136→            "silks": result.source_silks,
137→            "paddock": result.source_paddock,
138→            "empty_after": result.source_empty_after,
139→        },
140→        "destination": {
141→            "firemark": result.dest_firemark,
142→            "silks": result.dest_silks,
143→            "paddock": result.dest_paddock,
144→        },
145→        "drafted": drafted_json,
146→    });
147→
148→    match serde_json::to_string_pretty(&json_result) {
149→        Ok(json) => {
150→            vvco_out!(output, "{}", json);
151→            (0, output.vvco_finish())
152→        }
153→        Err(e) => {
154→            vvco_err!(output, "jjx_restring: error serializing output: {}", e);
155→            (1, output.vvco_finish())
156→        }
157→    }
158→    // lock released here
159→}
